h() //\u9012\u5F52\u51FA routes \u8868\n\n    window.addEventListener('hashchange', this.onHashchange.bind(this))\n    window.addEventListener('load', this.onHashchange.bind(this))\n  }\n\n  onHashchange() {\n    this.current = window.location.hash.slice(1)\n    this.matched = []\n    this.match()\n  }\n\n  match(routes) {\n    routes = routes || this.$options.routes\n    // \u9012\u5F52\u904D\u5386\n    for (const route of routes) {\n      // / \u8DEF\u7531\n      if (route.path === '/' && this.current === '/') {\n        this.matched.push(route)\n        return\n      }\n\n      // /helle/child \u5B50\u8DEF\u7531\n      if (route.path !== '/' && this.current.indexOf(route.path) !== -1) {\n        this.matched.push(route)\n        if (route.children) {\n          this.match(route.children) // \u9012\u5F52\u5B50\u8DEF\u7531\n        }\n        return\n      }\n    }\n  }\n}\n\n// _Vue \u5728 vue.use \u65F6\u4F20\u5165\nVueRouter.install = function (_Vue) {\n  Vue = _Vue //\u4FDD\u5B58\u53C2\u5165\u7684 Vue\uFF0C\u4E0D\u7528\u5F15\u5165\u4E5F\u80FD\u4F7F\u7528\n\n  // \u5168\u5C40\u6DF7\u5165\uFF0C\u6302\u8F7D $router\uFF0C\u5EF6\u8FDF\u4E0B\u9762\u903B\u8F91\u5230 router \u88AB\u6DFB\u52A0\u5230 new vue \u9009\u9879\u65F6\u624D\u6267\u884C\n  Vue.mixin({\n    beforeCreate() {\n      if (this.$options.router) {\n        Vue.prototype.$router = this.$options.router\n      }\n    }\n  })\n\n  // router-link,router-view\u7EC4\u4EF6\n  Vue.component('router-link', {\n    // template: '<a>aaa</a>'\n    props: {\n      to: {\n        type: String,\n        require: true\n      },\n    },\n\n    render(h) {\n      return h('a', {attrs: {href: '#' + this.to}}, this.$slots.default)\n    }\n  })\n\n  Vue.component('router-view', {\n    // template: '<a>bbb</a>'\n    render(h) {\n      // \u6807\u8BB0\u5F53\u524D router-view \u6DF1\u5EA6\n      this.$vnode.data.routerView = true\n\n      let depth = 0  // \u6DF1\u5EA6\n      let parent = this.$parent // vue \u4E2D vnode \u91CC\u6709\u4E00\u4E2A $parent \u5C5E\u6027\n\n      while (parent) {\n        const vnodeData = parent.$vnode && parent.$vnode.data\n        if (vnodeData && vnodeData.routerView) {\n          // \u5F53\u524D parent \u662F\u4E00\u4E2A router-view\n          depth++\n        }\n        parent = parent.$parent\n      }\n\n\n      // \u901A\u8FC7 depth \u83B7\u53D6\u5F53\u524D\u8DEF\u7531\u5BF9\u5E94\u7684\u7EC4\u4EF6\n      let component = null\n      const route = this.$router.matched[depth]\n      if (route) {\n        component = route.component\n      }\n      return h(component)\n    }\n  })\n}\n\nexport default VueRouter\n\n"})})]})}function h(e={}){let{wrapper:n}={...(0,u.a)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},50065:function(e,n,t){t.d(n,{Z:function(){return a},a:function(){return s}});var r=t(67294);let o={},u=r.createContext(o);function s(e){let n=r.useContext(u);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),r.createElement(u.Provider,{value:n},e.children)}}}]);